/// Projector that updates Profile projection from events
pub struct ProfileProjector<R: ProfileProjectionRepository> {
    repository: Arc<R>,
}

impl<R: ProfileProjectionRepository> ProfileProjector<R> {
    /// Create a new projector
    pub fn new(repository: Arc<R>) -> Self {
        Self { repository }
    }

    /// Rebuild all projections from event history
    pub async fn rebuild(&self) -> Result<u64> {
        self.repository.rebuild_all().await
    }

    /// Process a stored event from the event store
    ///
    /// This method dispatches the event to the appropriate handler based on event type.
    /// Returns Ok(true) if the event was processed, Ok(false) if it was skipped.
    pub async fn process_stored_event(&self, event: &crate::infrastructure::event_store::StoredEvent) -> Result<bool>
    where
        Self: ProfileEventHandler,
    {
        let sequence = event.sequence;

        match event.event_type.as_str() {
            "ProfileCreatedEvent" => {
                let created: ProfileCreatedEvent = serde_json::from_value(event.payload.clone())?;
                self.on_created(created, sequence).await?;
                Ok(true)
            }
            "ProfileUpdatedEvent" => {
                let updated: ProfileUpdatedEvent = serde_json::from_value(event.payload.clone())?;
                self.on_updated(updated, sequence).await?;
                Ok(true)
            }
            "ProfileDeletedEvent" => {
                let deleted: ProfileDeletedEvent = serde_json::from_value(event.payload.clone())?;
                self.on_deleted(deleted, sequence).await?;
                Ok(true)
            }
            _ => Ok(false), // Event type not handled by this projector
        }
    }
}

#[async_trait]
impl<R: ProfileProjectionRepository> ProfileEventHandler for ProfileProjector<R> {

    async fn on_created(&self, event: ProfileCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = ProfileProjection::new(
            event.user_id,
            event.first_name,
            event.middle_name,
            event.last_name,
            event.dob,
            event.pob,
            event.gender,
            event.phone_number,
            event.profile_picture_url,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: ProfileUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.first_name = event.first_name;
            projection.middle_name = event.middle_name;
            projection.last_name = event.last_name;
            projection.dob = event.dob;
            projection.pob = event.pob;
            projection.gender = event.gender;
            projection.phone_number = event.phone_number;
            projection.profile_picture_url = event.profile_picture_url;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: ProfileDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

